/**
 * Activities Page
 * Clean, minimal SaaS-style activities management page
 */

import React, { useState, useMemo, useEffect } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { Plus, ArrowUpDown, ArrowUp, ArrowDown, RotateCcw, Edit, Trash2 } from 'lucide-react';
import { Pagination, SearchFilterToolbar, BulkActionToolbar, Table as SharedTable } from '../components/shared';
import { getDefaultBulkStatusOptions } from '../components/shared/bulkStatusOptions';
import { __ } from '../lib/i18n';
import { usePermissions } from '../hooks/usePermissions';
import { useToast } from '../components/ui/toast';
import { apiClient } from '../lib/api';
import { Button } from '../components/ui/button';
import { PageHeader } from '../components/common/PageHeader';
import { Card, CardContent } from '../components/ui/card';
import { ConditionalRender } from '../components/ui/conditional-render';
import { ConfirmationDialog } from '../components/ui/confirmation-dialog';
import { IconSelector } from '../components/ui/icon-selector';
import type { IconPickerValue } from '../components/ui/icon-picker';

interface Activity {
  id: string | number;
  name: string;
  slug: string;
  description: string;
  icon?: IconPickerValue | null;
  status: string;
  created_at: string;
  updated_at: string;
  created_by: string;
  updated_by: string;
  created_by_name?: string;
  updated_by_name?: string;
}

const Activities: React.FC = () => {
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');
  const [sortBy, setSortBy] = useState('name');
  const [sortOrder, setSortOrder] = useState<'asc' | 'desc'>('asc');
  const [page, setPage] = useState(1);
  const [permanentDeleteConfirm, setPermanentDeleteConfirm] = useState<{ isOpen: boolean; activity: Activity | null }>({
    isOpen: false,
    activity: null,
  });
  const [individualActionConfirm, setIndividualActionConfirm] = useState<{ isOpen: boolean; action: string; activity: Activity | null }>({
    isOpen: false,
    action: '',
    activity: null,
  });
  const [selectedIds, setSelectedIds] = useState<(string | number)[]>([]);
  const [bulkAction, setBulkAction] = useState('');
  const [openDropdown, setOpenDropdown] = useState<string | number | null>(null);
  const [showColumnsDropdown, setShowColumnsDropdown] = useState(false);
  
  // Column visibility state with localStorage
  const [visibleColumns, setVisibleColumns] = useState(() => {
    const saved = localStorage.getItem('yatra-activities-columns');
    return saved ? JSON.parse(saved) : {
      name: true,
      description: true,
      status: true,
      created_at: false,
      updated_at: false,
      created_by_name: false,
      updated_by_name: false,
    };
  });

  const queryClient = useQueryClient();
  const { can } = usePermissions();
  const { showToast } = useToast();

  // Toggle column visibility
  const toggleColumn = (columnKey: string) => {
    const newVisibleColumns = {
      ...visibleColumns,
      [columnKey]: !visibleColumns[columnKey]
    };
    setVisibleColumns(newVisibleColumns);
    localStorage.setItem('yatra-activities-columns', JSON.stringify(newVisibleColumns));
  };

  // Close dropdown when clicking outside
  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      const target = event.target as HTMLElement;
      // Don't close if clicking on dropdown button or dropdown content
      if (target.closest('[data-dropdown-trigger]') || target.closest('[data-dropdown-content]') || 
          target.closest('[data-columns-trigger]') || target.closest('[data-columns-content]')) {
        return;
      }
      setOpenDropdown(null);
      setShowColumnsDropdown(false);
    };
    
    if (openDropdown !== null || showColumnsDropdown) {
      document.addEventListener('click', handleClickOutside);
      return () => document.removeEventListener('click', handleClickOutside);
    }
  }, [openDropdown, showColumnsDropdown]);

  // Build query params
  const queryParams = useMemo(() => {
    const params: Record<string, any> = {
      page,
      per_page: 10,
      orderby: sortBy,
      order: sortOrder,
    };

    if (searchTerm) {
      params.search = searchTerm;
    }

    if (statusFilter !== 'all') {
      params.status = statusFilter;
    }

    return params;
  }, [searchTerm, statusFilter, sortBy, sortOrder, page]);

  // Fetch status counts from API
  const { data: statsData } = useQuery({
    queryKey: ['activities-stats'],
    queryFn: async () => {
      try {
        const response = await apiClient.get('/activities/stats');
        return response;
      } catch (error: any) {
        return { all: 0, publish: 0, draft: 0, trash: 0 };
      }
    },
    enabled: can('yatra_view_trips'),
  });

  // Fetch activities from API
  const { data, isLoading, error } = useQuery({
    queryKey: ['activities', queryParams],
    queryFn: async () => {
      try {
        const response = await apiClient.get('/activities', { params: queryParams });
        return response;
      } catch (error: any) {
        showToast(error?.message || __('Failed to load activities', 'Failed to load activities'), 'error');
        throw error;
      }
    },
    enabled: can('yatra_view_trips'),
  });

  const activities = data?.data || [];
  const total = data?.total || 0;
  const totalPages = Math.ceil(total / 10);

  // Status counts from stats API
  const statusCounts = useMemo(() => {
    if (statsData) {
      return {
        all: statsData.all ?? 0,
        publish: statsData.publish ?? 0,
        draft: statsData.draft ?? 0,
        trash: statsData.trash ?? 0,
      };
    }
    return {
      all: 0,
      publish: 0,
      draft: 0,
      trash: 0,
    };
  }, [statsData]);

  // Bulk actions mutation
  const bulkMutation = useMutation({
    mutationFn: async ({ action, ids }: { action: string; ids: (string | number)[] }) => {
      return await apiClient.post('/activities/bulk', { action, ids });
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['activities'] });
      queryClient.invalidateQueries({ queryKey: ['activities-stats'] });
      showToast(__('Bulk action completed successfully', 'Bulk action completed successfully'), 'success');
      setSelectedIds([]);
      setBulkAction('');
    },
    onError: (error: any) => {
      showToast(error?.message || __('Failed to perform bulk action', 'Failed to perform bulk action'), 'error');
    },
  });





  const handleEdit = (activity: Activity) => {
    window.location.href = `${window.yatraAdmin?.siteUrl || ''}/wp-admin/admin.php?page=yatra&subpage=trips&tab=activities&action=edit&id=${activity.id}`;
  };



  const handlePermanentDelete = (activity: Activity) => {
    setPermanentDeleteConfirm({ isOpen: true, activity });
  };

  const confirmPermanentDelete = () => {
    if (permanentDeleteConfirm.activity) {
      bulkMutation.mutate({ action: 'delete', ids: [permanentDeleteConfirm.activity.id] });
      setPermanentDeleteConfirm({ isOpen: false, activity: null });
    }
  };

  const confirmIndividualAction = () => {
    if (individualActionConfirm.activity) {
      const action = individualActionConfirm.action === 'restore' ? 'restore' : 'trash';
      bulkMutation.mutate({ action, ids: [individualActionConfirm.activity.id] });
      setIndividualActionConfirm({ isOpen: false, action: '', activity: null });
    }
  };

  const handleCreateActivity = () => {
    window.location.href = `${window.yatraAdmin?.siteUrl || ''}/wp-admin/admin.php?page=yatra&subpage=trips&tab=activities&action=create`;
  };

  // Keep selection in sync with current page data
  useEffect(() => {
    setSelectedIds((prev) =>
      prev.filter((id) => activities.some((activity: Activity) => activity.id === id))
    );
  }, [activities]);




  const handleBulkApply = () => {
    if (!bulkAction) {
      showToast(__('Select a bulk action first.', 'Select a bulk action first.'), 'warning');
      return;
    }

    if (selectedIds.length === 0) {
      showToast(__('Select at least one activity.', 'Select at least one activity.'), 'warning');
      return;
    }

    // Execute bulk action (confirmation is now handled in BulkActionToolbar)
    bulkMutation.mutate({ action: bulkAction, ids: selectedIds });
  };

  const viewFilters = [
    { key: 'all', label: __('All', 'All'), count: statusCounts.all ?? 0 },
    { key: 'publish', label: __('Published', 'Published'), count: statusCounts.publish ?? 0 },
    { key: 'draft', label: __('Draft', 'Draft'), count: statusCounts.draft ?? 0 },
    { key: 'trash', label: __('Trash', 'Trash'), count: statusCounts.trash ?? 0 },
  ];

  const handleResetFilters = () => {
    setSearchTerm('');
    setStatusFilter('all');
    setSortBy('name');
    setSortOrder('asc');
    setPage(1);
    setSelectedIds([]);
    setBulkAction('');
  };

  const handleSort = (field: string) => {
    if (sortBy === field) {
      setSortOrder(sortOrder === 'asc' ? 'desc' : 'asc');
    } else {
      setSortBy(field);
      setSortOrder('asc');
    }
  };

  const getSortIcon = (field: string) => {
    if (sortBy !== field) {
      return <ArrowUpDown className="w-3.5 h-3.5 ml-1 text-gray-400" />;
    }
    return sortOrder === 'asc' 
      ? <ArrowUp className="w-3.5 h-3.5 ml-1 text-gray-600 dark:text-gray-300" />
      : <ArrowDown className="w-3.5 h-3.5 ml-1 text-gray-600 dark:text-gray-300" />;
  };

  const hasFilters = searchTerm || statusFilter !== 'all' || sortBy !== 'name' || sortOrder !== 'asc';

  return (
    <div className="space-y-3">
      {/* Permanent Delete Confirmation Dialog */}
      <ConfirmationDialog
        isOpen={permanentDeleteConfirm.isOpen}
        onClose={() => setPermanentDeleteConfirm({ isOpen: false, activity: null })}
        onConfirm={confirmPermanentDelete}
        title={__('Delete Activity Permanently', 'Delete Activity Permanently')}
        message={permanentDeleteConfirm.activity 
          ? __('Are you sure you want to permanently delete "{name}"? This action cannot be undone.', 'Are you sure you want to permanently delete "{name}"? This action cannot be undone.').replace('{name}', permanentDeleteConfirm.activity.name)
          : __('Are you sure you want to permanently delete this activity? This action cannot be undone.', 'Are you sure you want to permanently delete this activity? This action cannot be undone.')
        }
        confirmText={__('Delete Permanently', 'Delete Permanently')}
        cancelText={__('Cancel', 'Cancel')}
        variant="danger"
        isLoading={bulkMutation.isPending}
      />

      {/* Individual Action Confirmation Dialog */}
      <ConfirmationDialog
        isOpen={individualActionConfirm.isOpen}
        onClose={() => setIndividualActionConfirm({ isOpen: false, action: '', activity: null })}
        onConfirm={confirmIndividualAction}
        title={individualActionConfirm.action === 'trash' ? __('Move to Trash', 'Move to Trash') : __('Restore Activity', 'Restore Activity')}
        message={individualActionConfirm.activity 
          ? (individualActionConfirm.action === 'trash' 
              ? __('Are you sure you want to move "{name}" to trash?', 'Are you sure you want to move "{name}" to trash?').replace('{name}', individualActionConfirm.activity.name)
              : __('Are you sure you want to restore "{name}"?', 'Are you sure you want to restore "{name}"?').replace('{name}', individualActionConfirm.activity.name)
            )
          : (individualActionConfirm.action === 'trash' 
              ? __('Are you sure you want to move this activity to trash?', 'Are you sure you want to move this activity to trash?')
              : __('Are you sure you want to restore this activity?', 'Are you sure you want to restore this activity?')
            )
        }
        confirmText={individualActionConfirm.action === 'trash' ? __('Move to Trash', 'Move to Trash') : __('Restore', 'Restore')}
        cancelText={__('Cancel', 'Cancel')}
        variant="warning"
        isLoading={bulkMutation.isPending}
      />

      <PageHeader
        title={__('Activities', 'Activities')}
        description={__('Manage your travel activities and experiences', 'Manage your travel activities and experiences')}
        actionCapability="yatra_edit_trips"
        actions={
          <Button onClick={handleCreateActivity} className="flex items-center gap-2">
            <Plus className="w-4 h-4" />
            {__('Add New Activity', 'Add New Activity')}
          </Button>
        }
      />


      {/* Filters, Search, and Sorting - Always Visible */}
      <Card>
        <CardContent className="p-3">
          <SearchFilterToolbar
            searchTerm={searchTerm}
            onSearchChange={setSearchTerm}
            statusFilter={statusFilter}
            onStatusChange={(value) => {
              setStatusFilter(value);
              setPage(1);
              setSelectedIds([]);
              setBulkAction('');
            }}
            statusOptions={[
              { value: "all", label: __('All Status', 'All Status') },
              { value: "publish", label: __('Published', 'Published') },
              { value: "draft", label: __('Draft', 'Draft') },
              { value: "trash", label: __('Trash', 'Trash') }
            ]}
            sortBy={sortBy}
            onSortByChange={setSortBy}
            sortOrder={sortOrder}
            onSortOrderChange={setSortOrder}
            sortOptions={[
              { value: "name", label: __('Name', 'Name') },
              { value: "status", label: __('Status', 'Status') },
              { value: "created_at", label: __('Created At', 'Created At') },
              { value: "updated_at", label: __('Updated At', 'Updated At') }
            ]}
            onResetFilters={handleResetFilters}
            hasFilters={!!hasFilters}
            placeholder={__('Search activities...', 'Search activities...')}
          />
        </CardContent>
      </Card>

      <ConditionalRender capability="yatra_view_trips">
        {/* Table */}
        {error ? (
          <Card>
            <CardContent className="p-8 text-center text-red-500">
              {__('Error loading activities', 'Error loading activities')}
            </CardContent>
          </Card>
        ) : (
          <>
            <BulkActionToolbar
              selectedIds={selectedIds}
              bulkAction={bulkAction}
              setBulkAction={setBulkAction}
              onApply={handleBulkApply}
              onClearSelection={() => setSelectedIds([])}
              statusFilter={statusFilter}
              setStatusFilter={(value) => {
                setStatusFilter(value);
                setPage(1);
                setSelectedIds([]);
                setBulkAction('');
              }}
              statusOptions={viewFilters}
              showColumnsDropdown={showColumnsDropdown}
              setShowColumnsDropdown={setShowColumnsDropdown}
              columnOptions={[
                { key: 'name', label: __('Activity', 'Activity'), visible: visibleColumns.name },
                { key: 'description', label: __('Description', 'Description'), visible: visibleColumns.description },
                { key: 'status', label: __('Status', 'Status'), visible: visibleColumns.status },
                { key: 'created_at', label: __('Created Date', 'Created Date'), visible: visibleColumns.created_at },
                { key: 'updated_at', label: __('Updated Date', 'Updated Date'), visible: visibleColumns.updated_at },
                { key: 'created_by_name', label: __('Created By', 'Created By'), visible: visibleColumns.created_by_name },
                { key: 'updated_by_name', label: __('Updated By', 'Updated By'), visible: visibleColumns.updated_by_name }
              ]}
              onToggleColumn={toggleColumn}
              bulkMutationPending={bulkMutation.isPending}
              totalItems={activities.length}
              bulkActionOptions={getDefaultBulkStatusOptions(statusFilter)}
            />

            <Card className="overflow-visible">
              <CardContent className="p-0 overflow-visible">
                <SharedTable
                  data={activities}
                    columns={[
                      {
                        key: 'name',
                        label: __('Activity', 'Activity'),
                        sortable: true,
                        visible: visibleColumns.name,
                        render: (activity: Activity) => (
                          <div className="flex items-center gap-3">
                            {/* Icon/Image */}
                            <div className="w-10 h-10 rounded-lg bg-blue-100 dark:bg-blue-900/30 flex items-center justify-center flex-shrink-0">
                              {activity.icon ? (
                                activity.icon.type === 'image' ? (
                                  <img 
                                    src={activity.icon.value} 
                                    alt={activity.name}
                                    className="w-full h-full object-cover rounded-lg"
                                  />
                                ) : (
                                  <IconSelector 
                                    iconName={activity.icon.value} 
                                    className="w-5 h-5 text-blue-600 dark:text-blue-400" 
                                  />
                                )
                              ) : (
                                <div className="w-5 h-5 text-blue-600 dark:text-blue-400 flex items-center justify-center text-xs font-semibold">
                                  {activity.name.charAt(0).toUpperCase()}
                                </div>
                              )}
                            </div>
                            {/* Text */}
                            <div>
                              <a 
                                href={`${window.yatraAdmin?.siteUrl || ''}/wp-admin/admin.php?page=yatra&subpage=trips&tab=activities&action=edit&id=${activity.id}`}
                                className="font-medium text-blue-600 dark:text-blue-400 hover:text-blue-700 dark:hover:text-blue-300 hover:underline transition-colors cursor-pointer"
                              >
                                {activity.name}
                              </a>
                              <div className="text-sm text-gray-500 dark:text-gray-400">
                                {activity.slug}
                              </div>
                            </div>
                          </div>
                        )
                      },
                      {
                        key: 'description',
                        label: __('Description', 'Description'),
                        visible: visibleColumns.description,
                        render: (activity: Activity) => (
                          <span className={activity.status === 'trash' || statusFilter === 'trash' ? 'text-gray-400 dark:text-gray-600' : 'text-gray-600 dark:text-gray-400'}>
                            {activity.description || __('No description', 'No description')}
                          </span>
                        )
                      },
                      {
                        key: 'status',
                        label: __('Status', 'Status'),
                        sortable: true,
                        visible: visibleColumns.status,
                        render: (activity: Activity) => (
                          <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${
                            activity.status === 'trash' || statusFilter === 'trash'
                              ? 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400'
                              : activity.status === 'publish'
                                ? 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400'
                                : 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-400'
                          }`}>
                            {activity.status === 'trash' || statusFilter === 'trash'
                              ? __('Trash', 'Trash')
                              : activity.status === 'publish'
                                ? __('Published', 'Published')
                                : __('Draft', 'Draft')
                            }
                          </span>
                        )
                      },
                      {
                        key: 'created_at',
                        label: __('Created Date', 'Created Date'),
                        sortable: true,
                        visible: visibleColumns.created_at,
                        render: (activity: Activity) => (
                          <span className={activity.status === 'trash' || statusFilter === 'trash' ? 'text-gray-400 dark:text-gray-600' : 'text-gray-600 dark:text-gray-400'}>
                            {new Date(activity.created_at).toLocaleDateString('en-US', {
                              year: 'numeric',
                              month: 'short',
                              day: 'numeric',
                              hour: '2-digit',
                              minute: '2-digit'
                            })}
                          </span>
                        )
                      },
                      {
                        key: 'updated_at',
                        label: __('Updated Date', 'Updated Date'),
                        sortable: true,
                        visible: visibleColumns.updated_at,
                        render: (activity: Activity) => (
                          <span className={activity.status === 'trash' || statusFilter === 'trash' ? 'text-gray-400 dark:text-gray-600' : 'text-gray-600 dark:text-gray-400'}>
                            {new Date(activity.updated_at).toLocaleDateString('en-US', {
                              year: 'numeric',
                              month: 'short',
                              day: 'numeric',
                              hour: '2-digit',
                              minute: '2-digit'
                            })}
                          </span>
                        )
                      },
                      {
                        key: 'created_by_name',
                        label: __('Created By', 'Created By'),
                        visible: visibleColumns.created_by_name,
                        render: (activity: Activity) => (
                          <span className={activity.status === 'trash' || statusFilter === 'trash' ? 'text-gray-400 dark:text-gray-600' : 'text-gray-600 dark:text-gray-400'}>
                            {activity.created_by_name || __('Unknown', 'Unknown')}
                          </span>
                        )
                      },
                      {
                        key: 'updated_by_name',
                        label: __('Updated By', 'Updated By'),
                        visible: visibleColumns.updated_by_name,
                        render: (activity: Activity) => (
                          <span className={activity.status === 'trash' || statusFilter === 'trash' ? 'text-gray-400 dark:text-gray-600' : 'text-gray-600 dark:text-gray-400'}>
                            {activity.updated_by_name || __('Unknown', 'Unknown')}
                          </span>
                        )
                      }
                    ]}
                    actions={[
                      {
                        key: 'edit',
                        label: __('Edit', 'Edit'),
                        icon: <Edit className="w-4 h-4" />,
                        onClick: handleEdit,
                        condition: () => can('yatra_edit_trips'),
                      },
                      {
                        key: 'restore',
                        label: __('Restore', 'Restore'),
                        icon: <RotateCcw className="w-4 h-4" />,
                        onClick: (activity: Activity) => {
                          bulkMutation.mutate({ action: 'restore', ids: [activity.id] });
                        },
                        condition: (activity: Activity) => (activity.status === 'trash' || statusFilter === 'trash') && can('yatra_edit_trips'),
                      },
                      {
                        key: 'trash',
                        label: __('Move to Trash', 'Move to Trash'),
                        icon: <Trash2 className="w-4 h-4" />,
                        onClick: (activity: Activity) => {
                          bulkMutation.mutate({ action: 'trash', ids: [activity.id] });
                        },
                        condition: (activity: Activity) => activity.status !== 'trash' && statusFilter !== 'trash' && can('yatra_edit_trips'),
                      },
                      {
                        key: 'delete',
                        label: __('Delete Permanently', 'Delete Permanently'),
                        icon: <Trash2 className="w-4 h-4" />,
                        onClick: handlePermanentDelete,
                        condition: (activity: Activity) => (activity.status === 'trash' || statusFilter === 'trash') && can('yatra_delete_trips'),
                        variant: 'destructive',
                      }
                    ]}
                    isLoading={isLoading}
                    isError={!!error}
                    errorText={__('Error loading activities', 'Error loading activities')}
                    emptyText={__('No activities found', 'No activities found')}
                    emptyDescription={hasFilters 
                      ? __('Try adjusting your filters to see more results.', 'Try adjusting your filters to see more results.')
                      : __('Get started by creating your first activity.', 'Get started by creating your first activity.')
                    }
                    onCreateClick={can('yatra_edit_trips') ? handleCreateActivity : undefined}
                    onSort={handleSort}
                    getSortIcon={getSortIcon}
                    selectedItemIds={selectedIds}
                    onSelectItem={(id: string | number, checked: boolean) => {
                      if (checked) {
                        setSelectedIds([...selectedIds, id]);
                      } else {
                        setSelectedIds(selectedIds.filter(selectedId => selectedId !== id));
                      }
                    }}
                    onSelectAll={(checked: boolean) => {
                      if (checked) {
                        setSelectedIds(activities.map((a: Activity) => a.id));
                      } else {
                        setSelectedIds([]);
                      }
                    }}
                    isAllSelected={activities.length > 0 && selectedIds.length === activities.length}
                    getItemId={(activity: Activity) => activity.id}
                    getItemStatus={(activity: Activity) => activity.status}
                    statusFilter={statusFilter}
                    skeletonRows={5}
                  />
              </CardContent>
            </Card>

          </>
        )}
      </ConditionalRender>

      {/* Pagination */}
      {total > 0 && (
        <Card>
          <CardContent className="p-3">
            <Pagination
              currentPage={page}
              totalPages={totalPages}
              totalItems={total}
              itemsPerPage={10}
              onPageChange={setPage}
              itemName={__('activities', 'activities')}
            />
          </CardContent>
        </Card>
      )}
    </div>
  );
};

export default Activities;
